"use client";
import { useState } from "react";
import { Doctor } from "../../types";
import { formatCurrency } from "../../lib/utils";
import Badge from "../ui/Badge";
import Button from "../ui/Button";

interface Props {
  doctor: Doctor;
  onChannel: (doctor: Doctor) => void;
}

export default function DoctorCard({ doctor, onChannel }: Props) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      className="glass glass-hover animate-fade-up"
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        padding: "20px 24px",
        display: "flex",
        alignItems: "center",
        gap: 18,
      }}
    >
      {/* Avatar with glow */}
      <div style={{ position: "relative", flexShrink: 0 }}>
        <div
          style={{
            width: 52,
            height: 52,
            borderRadius: 16,
            background: "linear-gradient(135deg, #0ea5e9, #6366f1)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            color: "#fff",
            fontWeight: 800,
            fontSize: 16,
            fontFamily: "Syne, sans-serif",
            boxShadow: hovered
              ? "0 0 24px rgba(14,165,233,0.5)"
              : "0 0 12px rgba(14,165,233,0.25)",
            transition: "box-shadow 0.3s",
          }}
        >
          {doctor.initials}
        </div>
        {doctor.available && (
          <div
            style={{
              position: "absolute",
              bottom: -2,
              right: -2,
              width: 12,
              height: 12,
              borderRadius: "50%",
              background: "#22c55e",
              border: "2px solid #020818",
              boxShadow: "0 0 8px rgba(34,197,94,0.6)",
            }}
          />
        )}
      </div>

      {/* Info */}
      <div style={{ flex: 1, minWidth: 0 }}>
        <p style={{
          fontFamily: "Syne, sans-serif",
          fontWeight: 700,
          color: "#f1f5f9",
          fontSize: 15,
          marginBottom: 8,
          overflow: "hidden",
          textOverflow: "ellipsis",
          whiteSpace: "nowrap",
        }}>
          {doctor.name}
        </p>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
          <Badge variant="blue">{doctor.specialization}</Badge>
          <Badge variant="slate">{doctor.hospital}</Badge>
          {doctor.available
            ? <Badge variant="green">● Available</Badge>
            : <Badge variant="red">● Fully Booked</Badge>
          }
        </div>
      </div>

      {/* Fee + CTA */}
      <div style={{ textAlign: "right", flexShrink: 0 }}>
        <p style={{ color: "#4ade80", fontWeight: 700, fontSize: 16, marginBottom: 10 }}>
          {formatCurrency(doctor.fee)}
        </p>
        <Button
          variant={doctor.available ? "primary" : "secondary"}
          size="sm"
          disabled={!doctor.available}
          onClick={() => doctor.available && onChannel(doctor)}
        >
          {doctor.available ? "Channel 🩺" : "Unavailable"}
        </Button>
      </div>
    </div>
  );
}