import { Doctor } from "../../types";
import { formatCurrency } from "../../lib/utils";
import { TIME_SLOTS } from "../../data/mockData";
import Badge from "../ui/Badge";
import Button from "../ui/Button";
import TimeSlots from "./TimeSlots";

interface Props {
  doctor: Doctor;
  selectedSlot: string;
  onSelectSlot: (time: string) => void;
  onBook: () => void;
  onBack: () => void;
}

export default function DoctorDetail({ doctor, selectedSlot, onSelectSlot, onBook, onBack }: Props) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
      <Button variant="ghost" size="sm" onClick={onBack}>
        ← Back to Search
      </Button>

      {/* Doctor hero card */}
      <div
        className="glass animate-fade-up"
        style={{
          padding: 28,
          background: "linear-gradient(135deg, rgba(14,165,233,0.08) 0%, rgba(99,102,241,0.05) 100%)",
          position: "relative",
          overflow: "hidden",
        }}
      >
        {/* Decorative glow */}
        <div style={{
          position: "absolute",
          top: -60,
          right: -60,
          width: 200,
          height: 200,
          borderRadius: "50%",
          background: "radial-gradient(circle, rgba(14,165,233,0.1), transparent 70%)",
          pointerEvents: "none",
        }} />

        <div style={{ display: "flex", gap: 22, alignItems: "flex-start", position: "relative" }}>
          <div
            style={{
              width: 68,
              height: 68,
              borderRadius: 20,
              background: "linear-gradient(135deg, #0ea5e9, #6366f1)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              color: "#fff",
              fontWeight: 800,
              fontSize: 22,
              fontFamily: "Syne, sans-serif",
              flexShrink: 0,
              boxShadow: "0 0 32px rgba(14,165,233,0.4)",
            }}
          >
            {doctor.initials}
          </div>

          <div style={{ flex: 1, minWidth: 0 }}>
            <h2 style={{
              fontFamily: "Syne, sans-serif",
              fontWeight: 800,
              fontSize: 22,
              color: "#f1f5f9",
              marginBottom: 10,
            }}>
              {doctor.name}
            </h2>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginBottom: 10 }}>
              <Badge variant="blue">{doctor.specialization}</Badge>
              <Badge variant="purple">{doctor.hospital}</Badge>
              <Badge variant="green">● Available Today</Badge>
            </div>
            <p style={{ color: "#64748b", fontSize: 13 }}>
              {doctor.qualifications} · {doctor.experience} · {doctor.languages.join(", ")}
            </p>
          </div>

          <div style={{ textAlign: "right", flexShrink: 0 }}>
            <p style={{ color: "#64748b", fontSize: 11, marginBottom: 4 }}>Consultation Fee</p>
            <p style={{
              fontFamily: "Syne, sans-serif",
              fontWeight: 800,
              fontSize: 26,
              background: "linear-gradient(135deg, #4ade80, #22c55e)",
              WebkitBackgroundClip: "text",
              WebkitTextFillColor: "transparent",
              backgroundClip: "text",
            }}>
              {formatCurrency(doctor.fee)}
            </p>
          </div>
        </div>
      </div>

      {/* Time slots */}
      <TimeSlots
        slots={TIME_SLOTS}
        selected={selectedSlot}
        onSelect={onSelectSlot}
        onBook={onBook}
      />

      {/* Other hospitals */}
      {doctor.otherHospitals.length > 0 && (
        <div className="glass animate-fade-up-3" style={{ padding: 28 }}>
          <p style={{ fontSize: 11, fontWeight: 700, color: "#facc15", letterSpacing: 2, textTransform: "uppercase", marginBottom: 18 }}>
            🏥 Also Visits Other Hospitals
          </p>
          <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
            {doctor.otherHospitals.map(h => (
              <div
                key={h.name}
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  background: "rgba(14,28,54,0.5)",
                  borderRadius: 12,
                  padding: "14px 18px",
                  border: "1px solid rgba(56,189,248,0.08)",
                }}
              >
                <div>
                  <p style={{ fontWeight: 600, color: "#e2e8f0", fontSize: 14, marginBottom: 3 }}>{h.name}</p>
                  <p style={{ color: "#64748b", fontSize: 12 }}>{h.days} · {h.hours}</p>
                </div>
                <Badge variant="yellow">Other Location</Badge>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}