"use client";
import { TimeSlot } from "../../types";
import Button from "../ui/Button";

interface Props {
  slots: TimeSlot[];
  selected: string;
  onSelect: (time: string) => void;
  onBook: () => void;
}

export default function TimeSlots({ slots, selected, onSelect, onBook }: Props) {
  return (
    <div className="glass animate-fade-up-2" style={{ padding: 28 }}>
      <p style={{ fontSize: 11, fontWeight: 700, color: "#38bdf8", letterSpacing: 2, textTransform: "uppercase", marginBottom: 20 }}>
        ⏰ Available Time Slots
      </p>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 10, marginBottom: 24 }}>
        {slots.map((slot, i) => {
          const isSelected = selected === slot.time;
          return (
            <button
              key={slot.time}
              disabled={slot.booked}
              onClick={() => !slot.booked && onSelect(slot.time)}
              style={{
                padding: "10px 6px",
                borderRadius: 10,
                fontSize: 12,
                fontWeight: 600,
                fontFamily: "DM Sans, sans-serif",
                cursor: slot.booked ? "not-allowed" : "pointer",
                border: isSelected
                  ? "1px solid rgba(14,165,233,0.7)"
                  : slot.booked
                  ? "1px solid rgba(30,41,59,0.5)"
                  : "1px solid rgba(56,189,248,0.1)",
                background: isSelected
                  ? "linear-gradient(135deg, rgba(14,165,233,0.25), rgba(56,189,248,0.15))"
                  : slot.booked
                  ? "rgba(15,23,42,0.3)"
                  : "rgba(14,28,54,0.5)",
                color: isSelected
                  ? "#38bdf8"
                  : slot.booked
                  ? "#1e293b"
                  : "#94a3b8",
                textDecoration: slot.booked ? "line-through" : "none",
                boxShadow: isSelected ? "0 0 16px rgba(14,165,233,0.2)" : "none",
                transition: "all 0.2s",
                animationDelay: `${i * 0.03}s`,
              }}
              onMouseEnter={e => {
                if (!slot.booked && !isSelected) {
                  e.currentTarget.style.borderColor = "rgba(56,189,248,0.3)";
                  e.currentTarget.style.color = "#e2e8f0";
                  e.currentTarget.style.background = "rgba(14,165,233,0.08)";
                }
              }}
              onMouseLeave={e => {
                if (!slot.booked && !isSelected) {
                  e.currentTarget.style.borderColor = "rgba(56,189,248,0.1)";
                  e.currentTarget.style.color = "#94a3b8";
                  e.currentTarget.style.background = "rgba(14,28,54,0.5)";
                }
              }}
            >
              {slot.time}
            </button>
          );
        })}
      </div>

      {selected && (
        <div
          className="animate-scale-in"
          style={{
            background: "linear-gradient(135deg, rgba(14,165,233,0.12), rgba(99,102,241,0.08))",
            border: "1px solid rgba(14,165,233,0.25)",
            borderRadius: 14,
            padding: "18px 22px",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
          }}
        >
          <div>
            <p style={{ fontSize: 11, color: "#38bdf8", fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", marginBottom: 4 }}>
              Selected
            </p>
            <p style={{ fontFamily: "Syne, sans-serif", fontWeight: 700, color: "#f1f5f9", fontSize: 20 }}>
              {selected}
            </p>
          </div>
          <Button size="lg" onClick={onBook}>
            Book Now →
          </Button>
        </div>
      )}
    </div>
  );
}